// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---

// Encode a row's sort keys into an opaque base64 cursor.
function encodeCursor(row) {
    const payload = JSON.stringify({
        // ISO string preserves full timestamp precision across the round trip.
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

// Decode an opaque cursor back into its sort keys.
// Throws on anything malformed so the caller can return a 400.
function decodeCursor(cursor) {
    let parsed;
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        parsed = JSON.parse(json);
    } catch {
        throw new Error('Invalid cursor');
    }

    if (
        !parsed ||
        typeof parsed !== 'object' ||
        typeof parsed.created_at !== 'string' ||
        parsed.id === undefined ||
        parsed.id === null
    ) {
        throw new Error('Invalid cursor');
    }

    const createdAt = new Date(parsed.created_at);
    if (Number.isNaN(createdAt.getTime())) {
        throw new Error('Invalid cursor');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

// --- Handler ---

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.max(1, Math.min(limit, 100));

    const after = req.query.after;

    let sql;
    let params;

    if (after) {
        let cursor;
        try {
            cursor = decodeCursor(after);
        } catch {
            return res.status(400).json({ error: 'Invalid cursor' });
        }

        // Sort is (created_at DESC, id DESC). To get rows *after* the cursor,
        // we want rows that are strictly "less than" the cursor in that ordering.
        // The row-value comparison (created_at, id) < (cursorCreatedAt, cursorId)
        // expresses the compound condition correctly in one clause.
        // Fetch limit + 1 to detect whether more pages exist (N+1 trick).
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        // No cursor: return the first page, no cursor filter.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // N+1 trick: if we got an extra row, there are more pages.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore ? encodeCursor(posts[posts.length - 1]) : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}
```

## Notes on the implementation

- **Row-value comparison** `(created_at, id) < ($1, $2)` is the clean way to express the compound cursor. It's exactly equivalent to `created_at < $1 OR (created_at = $1 AND id < $2)` but is more readable and, importantly, lets PostgreSQL use a composite index on `(created_at DESC, id DESC)` efficiently. The `<` (rather than `<=`) makes the cursor exclusive, so the row you ended on isn't repeated.
- **`base64url`** avoids `+`/`/`/`=` characters that need URL-escaping in a query string. Plain `base64` works too if you URL-encode it.
- **`id` in the cursor** is what makes the pagination stable when multiple posts share the same `created_at` — without it, ties at a timestamp boundary could be skipped or duplicated.
- I clamped `limit`; the original didn't, but with N+1 it's cheap insurance against a client requesting a huge page.

## Why cursor-based is superior here

1. **Stable results under writes.** With OFFSET, inserting or deleting a post while a user pages shifts every subsequent row, causing skipped or duplicated items. A cursor anchors to a concrete `(created_at, id)` position, so new posts don't disrupt an in-progress traversal.
2. **Constant-time deep pages.** `OFFSET 100000` forces PostgreSQL to scan and discard 100k rows on every request — cost grows linearly with page depth. The cursor's `WHERE (created_at, id) < (...)` does an indexed seek straight to the right spot, so page 5000 is as fast as page 1.
3. **No expensive COUNT.** `COUNT(*)` on a large table is a full scan/index scan every request. Dropping it (and the `totalPages` it fed) removes that cost entirely; `hasMore` answers the only question the UI actually needs for "load more" / infinite scroll.

The trade-off: you lose random page access ("jump to page 47") and exact total counts — which is the right trade for a feed-style, descending-chronological list like this.

