// ─── Cursor Helpers ────────────────────────────────────────────────────────────

/**
 * Encodes a compound (created_at, id) cursor into an opaque base64 string.
 * created_at may be a Date object or an ISO string — both serialize correctly.
 */
function encodeCursor(created_at, id) {
    const payload = JSON.stringify({ created_at, id });
    return Buffer.from(payload).toString('base64url'); // URL-safe base64 (no +/=)
}

/**
 * Decodes a base64 cursor string back to { created_at, id }.
 * Throws a descriptive Error on any malformed input — caller must catch and 400.
 */
function decodeCursor(cursorStr) {
    let payload;

    try {
        const json = Buffer.from(cursorStr, 'base64url').toString('utf8');
        payload = JSON.parse(json);
    } catch {
        throw new Error('Cursor is not valid base64-encoded JSON.');
    }

    if (
        payload === null ||
        typeof payload !== 'object' ||
        !('created_at' in payload) ||
        !('id' in payload)
    ) {
        throw new Error('Cursor is missing required fields (created_at, id).');
    }

    // Ensure created_at is a recognisable timestamp
    if (isNaN(new Date(payload.created_at).getTime())) {
        throw new Error('Cursor contains an invalid created_at timestamp.');
    }

    return { created_at: payload.created_at, id: payload.id };
}


// ─── Route Handler ─────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // --- Parse & validate inputs ---
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const afterCursor = req.query.after ?? null;

    let cursor = null;
    if (afterCursor !== null) {
        try {
            cursor = decodeCursor(afterCursor);
        } catch (err) {
            return res.status(400).json({ error: `Invalid cursor: ${err.message}` });
        }
    }

    // --- Build query (no OFFSET, no COUNT) ---
    //
    // Sort order is (created_at DESC, id DESC), so "after the cursor" means
    // rows whose (created_at, id) tuple is strictly smaller — either an earlier
    // timestamp, or an equal timestamp with a smaller id.
    //
    // We fetch limit+1 rows. If we actually get limit+1, there are more pages;
    // we strip the extra row and set hasMore=true. No COUNT(*) needed.

    let rows;

    if (cursor) {
        const { rows: fetched } = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (
                      created_at < $1
                      OR (created_at = $1 AND id < $2)
                    )
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1]
        );
        rows = fetched;
    } else {
        // First page — no cursor predicate at all
        const { rows: fetched } = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]
        );
        rows = fetched;
    }

    // --- Apply N+1 trick ---
    const hasMore = rows.length > limit;
    const posts   = hasMore ? rows.slice(0, limit) : rows;

    // --- Build next cursor from the last returned row ---
    const lastPost    = posts.at(-1);          // undefined when result set is empty
    const nextCursor  = hasMore && lastPost
        ? encodeCursor(lastPost.created_at, lastPost.id)
        : null;

    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,   // null on the final page or an empty result
            limit,
        },
    });
}
```

---

## Why cursor-based pagination is superior here

| Concern | Offset-based | Cursor-based |
|---|---|---|
| **Consistency under writes** | A new post inserted between page 1 and page 2 shifts every row's offset — page 2 repeats a row from page 1 (or skips one). | The cursor points to a specific row by value. Inserts before the cursor are invisible; the page boundary never shifts. |
| **Cost at large offsets** | `OFFSET 10000` forces PostgreSQL to read and discard 10 000 rows before returning anything. Gets slower the deeper you go. | The compound WHERE clause can hit an index on `(created_at DESC, id DESC)` and start reading from exactly the right place — O(1) regardless of depth. |
| **COUNT(*) requirement** | Needed to compute `totalPages`, which is expensive on large tables (sequential scan or a non-trivial index scan). | Eliminated entirely. `hasMore` is derived from fetching one extra row — zero additional queries. |
| **Resumability** | A page number is meaningless after data changes. Saving `page=47` in a URL may not show the same content tomorrow. | A cursor encodes an exact position that remains stable across unrelated writes. |

**The one trade-off**: clients lose random-access pagination ("jump to page 7"). Cursor pagination is sequential by design, which is the correct model for infinite-scroll feeds, log tails, and API consumers iterating a result set programmatically.

